function getBase64String(imgUrl, callback) {
  const img = new Image();
  img.crossOrigin = 'Anonymous';
  img.onload = () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    let dataURL;
    canvas.height = img.naturalHeight;
    canvas.width = img.naturalWidth;
    ctx.drawImage(img, 0, 0);
    ctx.imageSmoothingEnabled = false;
    dataURL = canvas.toDataURL();
    // console.log(dataURL);
    callback(dataURL)
  };
  img.src = imgUrl;
}

function _addWatermarkImg(thumImg, bestFit, zImg, name, that) {
  var imageRatioX = that.options.data.zWidth / that.options.data.bestfitWidth;
  var imageRatioY = that.options.data.zHeight / that.options.data.bestfitHeight;
  var scale = Math.min(imageRatioX, imageRatioY);
  var watermarkWidth = getTextWidth(name, 1);
  var repeatX = that.options.data.bestfitWidth;
  var repeatY = that.options.data.bestfitHeight;

  that.options.data.isSmallImg = false;
  if (watermarkWidth > that.options.data.bestfitWidth || 30 > that.options.data.bestfitHeight) {
    //if (true) {
    that.options.data.isSmallImg = true;

    var designX = repeatX = parseInt(watermarkWidth / that.options.data.bestfitWidth) + 1;
    repeatX = that.options.data.bestfitWidth * repeatX;
    var designY = repeatY = parseInt(30 / that.options.data.bestfitHeight) + 1;
    repeatY = that.options.data.bestfitHeight * repeatY;

    if (Math.round(repeatY / repeatX) < 1) {
      // var repeatX = 1;
      var X = 1;
    } else {
      var X = Math.round(repeatY / repeatX)
    }
    if (Math.round(repeatX / repeatY) < 1) {
      // var repeatY = 1;
      var Y = 1;
    } else {
      var Y = Math.round(repeatX / repeatY)
    }
    var repeatX = repeatX * X;
    var repeatY = repeatY * Y;

    that.options.data.bestfitWidth = repeatX;
    that.options.data.bestfitHeight = repeatY;

    var greater = (designX > designY ? designX : designY);
    // var xPXInch = repeatX / (parseFloat(that.options.data.designWidth) * greater);
    // var yPXInch = repeatY / (parseFloat(that.options.data.designHeight) * greater);
    var xPXInch = repeatX;
    var yPXInch = repeatY;

    // var actualBGSizeX = that.options.data.ScreenDPIXDefault / xPXInch;
    // var actualBGSizeY = that.options.data.ScreenDPIYDefault / yPXInch;

    var bg = $('#_zoomImage1').css('background-size').split(' ');
    if (bg[0].match(/px/)) {
      bg[0] = parseFloat(bg[0].replace('px', ''));
      bg[1] = parseFloat(bg[1].replace('px', ''));

      // $('#_zoomImage1').css('background-size', (bg[0] * actualBGSizeX) + 'px ' + (bg[1] * actualBGSizeY) + 'px');
      // $('#_mainBackgroundDiv').css('background-size', (bg[0] * actualBGSizeX) + 'px ' + (bg[1] * actualBGSizeY) + 'px');
      $('#_zoomImage1').css('background-size', (that.options.data.bestfitWidth) + 'px ' + (that.options.data.bestfitHeight) + 'px');
      $('#_mainBackgroundDiv').css('background-size', (that.options.data.bestfitWidth) + 'px ' + (that.options.data.bestfitHeight) + 'px');
    }


    if (watermarkWidth > that.options.data.bestfitWidth && 30 > that.options.data.bestfitHeight) {
      that.options.data.xPXInch = Math.round(xPXInch);
      that.options.data.yPXInch = Math.round(yPXInch);
      that.options.data.xPXCent = xPXInch / 2.54;
      that.options.data.yPXCent = yPXInch / 2.54;

      addInchRulerI(that.options.data.xPXInch, that.options.data.yPXInch);
      addCentRulerI(that.options.data.xPXCent, that.options.data.yPXCent);
    }


    getBase64String(bestFit, (dataUrl) => {
      bestFit = dataUrl;
      txt = '<div id="_createRepeat" style="display:block;position:absolute;width:' + repeatX + 'px;height:' + repeatY + 'px;background-repeat:repeat;background-image:url(' + bestFit + ');"></div>';
      txt += '<div id="_createRepeatUpper" style="display:block;position:absolute;width:' + repeatX + 'px;height:' + repeatY + 'px;background-repeat:repeat;background:white;">';
      // $('#_mainBackgroundDiv').append(txt);
      $('body').append(txt);
      html2canvas($("#_createRepeat"), {
        allowTaint: true,
        useCORS: true
      }).then(function(canvas) {
        canvas.getContext('2d');
        $('#_createRepeat').remove();
        $('#_createRepeatUpper').remove();
        bestFitN = canvas.toDataURL("image/jpeg", 1.0);
        var repeatX = parseInt((watermarkWidth * scale) / that.options.data.zWidth) + 1;
        repeatX = that.options.data.zWidth * repeatX;
        var repeatY = parseInt((30 * scale) / that.options.data.zHeight) + 1;
        repeatY = that.options.data.zHeight * repeatY;
        if (Math.round(repeatY / repeatX) < 1) {
          // var repeatX = 1;
          var X = 1;
        } else {
          var X = Math.round(repeatY / repeatX)
        }
        if (Math.round(repeatX / repeatY) < 1) {
          // var repeatY = 1;
          var Y = 1;
        } else {
          var Y = Math.round(repeatX / repeatY)
        }
        var repeatX = repeatX * X;
        var repeatY = repeatY * Y;

        that.options.data.zWidth = repeatX;
        that.options.data.zHeight = repeatY;
        getBase64String(zImg, (dataUrl) => {
          zImg = dataUrl;
          txt = '<div id="_createRepeat" style="display:block;position:absolute;width:' + repeatX + 'px;height:' + repeatY + 'px;background-repeat:repeat;background-image:url(' + zImg + ');"></div>';
          txt += '<div id="_createRepeatUpper" style="display:block;position:absolute;width:' + repeatX + 'px;height:' + repeatY + 'px;background-repeat:repeat;background:white;">';
          // $('#_mainBackgroundDiv').append(txt);
          $('body').append(txt);
          html2canvas($("#_createRepeat"), {
            allowTaint: true,
            useCORS: true
          }).then(function(canvas) {
            canvas.getContext('2d');
            $('#_createRepeat').remove();
            $('#_createRepeatUpper').remove();
            zImgN = canvas.toDataURL("image/jpeg", 1.0);
            _createAddWatermark(thumImg, bestFitN, zImgN, name, that);
          });
        });
      });
    });
  } else {
    _createAddWatermark(thumImg, bestFit, zImg, name, that);
  }
}

function _createAddWatermark(thumImg, bestFit, zImg, name, that) {
  var imageRatioX = that.options.data.zWidth / that.options.data.bestfitWidth;
  var imageRatioY = that.options.data.zHeight / that.options.data.bestfitHeight;
  var scale = Math.min(imageRatioX, imageRatioY);

  var options = {
    init: function(img) {
      img.crossOrigin = 'anonymous';
    }
  };

  var rotateB = function(target) {
    var context = target.getContext('2d');
    var text = name;
    var metrics = context.measureText(text);
    var watermarkWidth = getTextWidth(text, 1); // 23 px for X character width
    var watermarkHeight = 30;
    var x = ((target.width - watermarkWidth) / 2);
    var y = ((target.height - watermarkHeight) / 2);
    context.translate(x, y);
    context.globalAlpha = 0.5;
    context.fillStyle = 'gray';
    context.font = '30px Josefin Slab';
    context.rotate(0 * Math.PI / 180);
    context.fillText(text, 0, 0);
    return target;
  };

  var rotateZ = function(target) {
    var context = target.getContext('2d');
    var text = name;
    var metrics = context.measureText(text);

    var watermarkWidth = getTextWidth(text, scale); // 23 px for X character width
    var watermarkHeight = 30 * scale;
    // var watermarkWidth = noOfChar * watermarkHeight;

    var x = ((target.width - watermarkWidth) / 2);
    var y = ((target.height - watermarkHeight) / 2);

    context.translate(x, y);
    context.globalAlpha = 0.5;
    context.fillStyle = 'gray';
    var size = 30 * scale;
    // var size = (0.150*that.options.data.bestfitWidth) * scale;

    context.font = size + 'px Josefin Slab';
    // context.shadowBlur = 20;
    // context.shadowColor = "gray";
    context.rotate(0 * Math.PI / 180);
    context.fillText(text, 0, 0);
    return target;
  };

  if (!that.options.data.isSmallImg) {
    watermark([thumImg], options)
      .image(rotateB)
      .then(function(img) {
        $('._galleryList').eq(0).find('[bestfit]').css('background-image', 'url(' + ($(img).attr('src')) + ')');
      });
  }

  watermark([bestFit], options)
    .image(rotateB)
    .then(function(img) {
      if (that.options.data.isSmallImg) {
        $('._galleryList').eq(0).find('[bestfit]').css('background-image', 'url(' + ($(img).attr('src')) + ')');
      }

      $('#_zoomImage1').attr('bestfit', ($(img).attr('src')));
      $('._galleryList').eq(0).find('[bestfit]').attr('bestfit', ($(img).attr('src')));

      if (!$('#_zoomImage1 canvas').is(':visible')) {
        $('#_zoomImage1').css('background-image', 'url(' + ($(img).attr('src')) + ')');
      }
      $('#_mainBackgroundDiv').css('background-image', 'url(' + ($(img).attr('src')) + ')');
    });

  watermark([zImg], options)
    .image(rotateZ)
    .then(function(img) {
      $('#_zoomImage1').attr('data-zoom-image', ($(img).attr('src')));
      $('._galleryList').eq(0).find('[bestfit]').attr('data-zoom-image', ($(img).attr('src')));
    });
}

function getTextWidth(inputText, scale) {
  font = "30px Josefin Slab";

  canvas = document.createElement("canvas");
  context = canvas.getContext("2d");
  context.font = font;
  width = context.measureText(inputText).width;
  formattedWidth = Math.ceil(width) + "px";
  return parseInt(formattedWidth) * scale;
}

function exitHandler(that) {
  if (!document.fullscreenElement && !document.webkitIsFullScreen && !document.mozFullScreen && !document.msFullscreenElement) {
    $('#_fullScreenBtn').attr('status', 'open');
    $('#_fullScreenBtn').css('background-image', 'url(' + that.options.openfullScreenIcon + ')');
    _removeHeader();
  }
  setTimeout(function() {
    addInchRulerI(that.options.data.xPXInch, that.options.data.yPXInch);
    addCentRulerI(that.options.data.xPXCent, that.options.data.yPXCent);
  }, 300);
}

function _openFullscreen() {
  var elem = document.getElementById("_fullScreenDiv");
  if (elem.requestFullscreen) {
    elem.requestFullscreen();
  } else if (elem.mozRequestFullScreen) {
    /* Firefox */
    elem.mozRequestFullScreen();
  } else if (elem.webkitRequestFullscreen) {
    /* Chrome, Safari and Opera */
    elem.webkitRequestFullscreen();
  } else if (elem.msRequestFullscreen) {
    /* IE/Edge */
    elem.msRequestFullscreen();
  }
  _addHeader();
}

function _closeFullscreen() {
  var elem = document.getElementById("_fullScreenDiv");
  if (document.exitFullscreen) {
    document.exitFullscreen();
  } else if (document.mozCancelFullScreen) {
    /* Firefox */
    document.mozCancelFullScreen();
  } else if (document.webkitExitFullscreen) {
    /* Chrome, Safari and Opera */
    document.webkitExitFullscreen();
  } else if (document.msExitFullscreen) {
    /* IE/Edge */
    document.msExitFullscreen();
  }
  _removeHeader();
}

