function addQ3DModel(that, clicked, isDesignI) {
  var loaderHide = false;
  var data = that.options.data;
  var sURL = data.q3dData.serviceUrl + "/ProductQueryService";
  var defaultZoom = (data.q3dData.defaultsZoom == undefined ? false : parseInt(data.q3dData.defaultsZoom));
  if (!data.q3dData.isTailori) {
    _fullViewConfig = new Tds.DotNetQ3d({
      ServiceUrl: data.q3dData.serviceUrl,
      Key: data.q3dData.key,
      isQ3d: false,
      OrganisationId: data.q3dData.OrganisationId,
      container: "_zoomImage1",
      dracoPath: 'draco/',
      texture: data.q3dData.texture,
      Dpi: Math.round(data.zxPXInch),
      twidth: parseFloat(data.designWidth),
      theight: parseFloat(data.designHeight),
      isSkinColor: 'rgb(' + data.q3dData.skinColorRGB + ')',
      isShoesColor: 'rgb(' + data.q3dData.shoesRGB + ')',
      onConfigLoad: function() {

        OnConfigLoad();
      },
      onObjectLoad: function(id) {
        console.log(id);
        $("#" + id.toString()).find("._loader").hide();
      },
      onObjectClick: function(name, orderNo) {
        // console.log("Group Name : " + name);
        // console.log("Group Order Number : " + orderNo);
      },
      onTextureChange: function() {
        OnTextureChange();
        // console.log("On Texture change");
      },
      onImageChange: function() {
        // console.log("On Image change");
      }
    });
  }

  setTimeout(function() {
    if (!loaderHide) {
      $('._loader').hide(500);
    }
  }, 10000)
}

var OnConfigLoad = function(type) {

  loaderHide = true;
  $('#_centerLoader').hide();
  $('._loader').hide();
  var txt = "<center>",
    fst = true;
  // var threeDImages = _fullViewConfig.getThreeDImages();
  var threeDImages = _fullViewConfig.getThreeDImages(that.options.data.productName);

  for (var s in threeDImages) {
    if (threeDImages.hasOwnProperty(s)) {
      txt += '<div class="_q3dModel" id="' + threeDImages[s].id + '" value="' + ((threeDImages[s].name).toLowerCase()).replace(/ /g, "_") + '" index="' + threeDImages[s].id + '" style="cursor: pointer;width: 90%;height: 100px;margin-top: 25px;position:relative;">';
      txt += '<div class="_loader" style="position: absolute;margin-top: 0px;display:block;"><img style="width:100%;height:100%;" src="' + that.options.loader + '"></div>';
      // if (_fullViewConfig.getThreeDImageSize(threeDImages[s].id.toString()).isThreeD) {
      if (threeDImages[s].isThreeD) {
        var q3dLogo = that.options.q3dLogo;
        var isTD = "isthreed='true'";
      } else {
        var q3dLogo = "";
        var isTD = "isthreed='true'";
      }
      txt += '<div class="_q3dIcon" ' + isTD + ' style="position: absolute;right: 0px;width: 40px;height: 20px;margin:5px 0px;background-image:url(' + q3dLogo + ');background-repeat: no-repeat;background-size: 100%;"></div>';

      txt += '<div class="_active">';
      txt += '<img width="100%" height="100px" style="object-fit: contain;" src="' + threeDImages[s].imgsrc.replace('t.png', 't.jpg') + '">';
      txt += '<div style="width: 100%;height: 20px;margin-top: -4px;word-wrap: break-word;font-size: 11px;"> <span>' + ((threeDImages[s].name).toLowerCase()).replace(/ /g, "_") + '</span>';
      txt += '</div></div></div>';
    }
  }

  txt += '</center>';
  $('#_sliderDiv center').eq(1).remove();
  $('#_sliderDiv').append(txt);
  if (!that.options.data.displayDesignName) {
    $('#_sliderDiv span').parent().hide();
  }

  setTimeout(function() {
    $('._loader').hide(500);
  }, 1000);

  $('._q3dModel').unbind('click');
  $('._q3dModel').on('click', function() {
    if (!$(this).hasClass('_selected')) {

      if ($(this).find("._loader").css('display') == 'block') {
        console.log("Model not loaded");
        return;
      }

      $('._ZoomContainer').remove();
      // $('#_zoomImage1 canvas').show();
      $('#_zoomImage1 canvas').show();
      setTimeout(function() {
      $('#_zoomImage1 canvas').hide();
      }, 2000);
      $('#_resetBtn').show();
      $('#_nextBtn').show();
      $('#_previousBtn').show();
      $('#centerZoomIcon').show();
      // $('#_fullScreenBtn').show();
      // $('#_infoBtn').hide();
      $('#_info').hide();
      $('#_colorwayGallary').hide();
      // $('#_addToCart').hide();
      $('#_addToFav').hide();
      $('#_actualBtnFront').hide();
      $('#_infoTable').hide();
      $('#_previousBtn').css('left', '10px');
      $('#centerZoomIcon').hide();
      $('._rulerH,._rulerV,._rulerHCent,._rulerVCent').hide();
      $('._active').css('border', '');
      $('._active').css('transform', '');
      $('._q3dModel').css('border', '');
      $('._q3dModel').css('transform', '');
      $(this).css('border', '0.5px solid black');
      $(this).css('transform', 'scale(1.09)');

      $('._q3dModel').removeClass('_selected');
      $('._active').removeClass('_selected');
      $(this).addClass('_selected');

      $('._active').css('border-width', '');
      $('._active').css('border-style', '');
      $('._active').css('border-color', '');
      $('._q3dModel').css('border-width', '');
      $('._q3dModel').css('border-style', '');
      $('._q3dModel').css('border-color', '');

      $(this).css('border-width', '6px 1px 1px');
      $(this).css('border-style', 'solid');
      $(this).css('border-color', 'rgb(19, 102, 185)');

      $('#_zoomImage').hide();
      // _fullViewConfig.showThreeDImage($(this).attr("id"));
      // _fullViewConfig.loadThreeDImage($(this).attr("id"));
      _fullViewConfig.loadThreeDImage($(this).attr("id"), that.options.data.q3dData.texture, parseFloat(that.options.data.designWidth), parseFloat(that.options.data.designHeight));
      $('#_zoomImage1').css('background-image', '');
      $('#_zoomImage1').css('background-size', '');
      if ($(this).find('._q3dIcon').attr('isthreed') == 'false') {
        $('#_zoomImage1').css('background-color', 'white');
      } else {
        $('#_zoomImage1').css('background-image', 'radial-gradient(rgb(243, 243, 237), rgb(111, 111, 111))');
      }
    }
  })

  $('#_resetBtn').unbind('click');
  $('#_resetBtn').on('click', function() {
    _fullViewConfig.resetModel();
  })
  setTimeout(function() {
    $("#_zoomImage1 canvas")
      .css('cursor', 'grab')
      .mouseup(function() {
        $(this).css('cursor', 'grab');
      })
      .mousedown(function() {
        $(this).css('cursor', 'grabbing');
      });
  }, 1000)
  returnCallback(that);
}

